#include<bits/stdc++.h>
using namespace std;
bool panzi(int x){
	for(int i=2;i*i<=x;i++) if(x%i==0) return 0;
	return 1;
}
bool panshu(int x){
	if(panzi(x)&&panzi(x%10*10+x/10)){
		return 1;
	}else{
		return 0;
	}
}
int main(){
	int a,b,ans;
	cin>>a>>b;
	for(int i=a;i<=b;i++) if(panshu(i)) cout<<i<<"\n";
	return 0;
}
